    /**
     * The stored documents were normalized under a *different* profile/options.
     * Querying as-is would return wrong results — regenerate (via `reindex`,
     * `withConfigRebuilding`, or `withOptionsRebuilding`) before use.
     */
    CONFIG_CHANGED;

    


    companion object
}


