/**
 * An error surfaced across the FFI boundary by `SearchEngine`.
 */
sealed class SearchException: kotlin.Exception() {
    
    /**
     * An underlying SQLite / storage failure; the associated string is its
     * message.
     */
    class Db(
        
        val v1: kotlin.String
        ) : SearchException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    /**
     * The on-disk index was built with a different normalization profile
     * than the one requested. Indexed text is profile-specific, so the index
     * must be rebuilt to change profiles. `stored` is the profile recorded in
     * the index; `requested` is the one just asked for.
     */
    class ConfigMismatch(
        
        val `stored`: kotlin.String, 
        
        val `requested`: kotlin.String
        ) : SearchException() {
        override val message
            get() = "stored=${ `stored` }, requested=${ `requested` }"
    }
    
    /**
     * The index was created with a different `field_bits` than requested. The
     * id packing is encoding-specific and fixed at creation, so this is not
     * auto-rebuilt: open with `field_bits: None` to adopt the stored value, or
     * call `change_field_bits` to re-pack the index. `stored` is the value
     * recorded in the index; `requested` is the one just asked for.
     */
    class FieldBitsMismatch(
        
        val `stored`: kotlin.UByte, 
        
        val `requested`: kotlin.UByte
        ) : SearchException() {
        override val message
            get() = "stored=${ `stored` }, requested=${ `requested` }"
    }
    

    


    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<SearchException> {
        override fun lift(error_buf: RustBuffer.ByValue): SearchException = FfiConverterTypeSearchError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeSearchError : FfiConverterRustBuffer<SearchException> {
    override fun read(buf: ByteBuffer): SearchException {
        

        return when(buf.getInt()) {
            1 -> SearchException.Db(
                FfiConverterString.read(buf),
                )
            2 -> SearchException.ConfigMismatch(
                FfiConverterString.read(buf),
                FfiConverterString.read(buf),
                )
            3 -> SearchException.FieldBitsMismatch(
                FfiConverterUByte.read(buf),
                FfiConverterUByte.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: SearchException): ULong {
        return when(value) {
            is SearchException.Db -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is SearchException.ConfigMismatch -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`stored`)
                + FfiConverterString.allocationSize(value.`requested`)
            )
            is SearchException.FieldBitsMismatch -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterUByte.allocationSize(value.`stored`)
                + FfiConverterUByte.allocationSize(value.`requested`)
            )
        }
    }

    override fun write(value: SearchException, buf: ByteBuffer) {
        when(value) {
            is SearchException.Db -> {
                buf.putInt(1)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is SearchException.ConfigMismatch -> {
                buf.putInt(2)
                FfiConverterString.write(value.`stored`, buf)
                FfiConverterString.write(value.`requested`, buf)
                Unit
            }
            is SearchException.FieldBitsMismatch -> {
                buf.putInt(3)
                FfiConverterUByte.write(value.`stored`, buf)
                FfiConverterUByte.write(value.`requested`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



/**
 * Which query algorithm `SearchEngine::search` uses.
 */

enum class SearchStrategy {
    
    /**
     * Trigram FTS5 + bm25, with a LIKE fallback for queries shorter than 3 chars.
     */
    TRIGRAM_BM25,
    /**
     * Substring match (`LIKE '%q%'`) for every query.
     */
    SUBSTRING,
    /**
     * Prefix match (`LIKE 'q%'`) for every query.
     */
    PREFIX,
    /**
     * Suffix match (`LIKE '%q'`) for every query.
     */
    SUFFIX,
    /**
     * Every whitespace-separated term must appear (substring), order-independent.
     */
    ALL_TERMS,
    /**
     * Character-trigram set similarity (Jaccard); ranked by 1 − similarity.
     */
    FUZZY_TRIGRAM,
    /**
     * Typo-tolerant: min Levenshtein distance to any word in the doc.
     */
    LEVENSHTEIN,
    /**
     * Like `Levenshtein`, but an adjacent transposition counts as one edit.
     */
    DAMERAU_LEVENSHTEIN;

    


    companion object
}


